/**
 * useTableState — all React state, SWR data fetching, and derived values
 * for the DataTable component.
 *
 * No JSX, no PrimeReact UI components — the logic here is platform-agnostic
 * and can be reused in a future React Native implementation.
 *
 * @typeParam T — the row data type, propagated from `<Datatable<T> ... />`.
 */
import {
    useCallback,
    useEffect,
    useImperativeHandle,
    useMemo,
    useRef,
    useState,
} from "react";
import type {
    IColumnBase,
    IDataTableProps,
    IDatatableRefValues,
    IPaginationRequest,
    PaginationState,
    ServerResponse,
    IPaginationResponse,
} from "@lmb-it/kitsconcerto-types";
import {
    type DataTableExpandedRows,
    type DataTableFilterMeta,
    type DataTableProps,
    type DataTableSortMeta,
    type DataTableStateEvent,
    type DataTableValueArray,
    type DataTable as PrimeTableType,
} from "primereact/datatable";
import { type PaginatorPageChangeEvent } from "primereact/paginator";
import { isEqual } from "lodash";
import useSWR, { type Fetcher, type MutatorCallback } from "swr";
import { fixData, revertFilter } from "../utils";
import { matchModeDefaultValues } from "../components/assets";

export function buildFiltersDefault(columns: IDataTableProps["columns"]): DataTableFilterMeta {
    const filters: DataTableFilterMeta = {};
    columns.forEach((col) => {
        const name = col.name;
        if (col.label !== "#" && col.filter && name) {
            filters[name] = {
                value: null,
                matchMode: matchModeDefaultValues[col.filter.type],
            };
        }
    });
    return filters;
}

export function useTableState<T extends Record<string, any> = any>(
    props: IDataTableProps<T>,
    ref: IDataTableProps<T>["ref"],
) {
    const {
        id,
        columns,
        onRowSelect,
        selectionMode = "single",
        onSelectChange,
        tableSize = "small",
        resizableColumns = false,
        scrollHeight,
        stateful = true,
        skeleton = true,
        globalSearch = true,
        headless = false,
        multiSorting,
        rowLockable,
        rowExpansionTemplate,
        service,
        serviceRevalidateDeps,
        keyColumn = "uuid",
        data: staticData,
        exportPDFButton,
        exportCSVButton,
        moreButtons,
        tableTitle,
        debounceFilterWaitTime = 500,
        filterMode = 'enter',
    } = props;

    const filtersDefault = useMemo(
        () => buildFiltersDefault(columns),
        // computed once — column filter definitions don't change after mount
        // eslint-disable-next-line react-hooks/exhaustive-deps
        [],
    );

    const tableRef = useRef<PrimeTableType<T[]>>(null);

    const [isLoading, setIsLoading] = useState<boolean>(false);
    const hasInitialData = useRef<boolean>(false);
    const [dataList, setDataList] = useState<T[]>([]);
    const [globalFilterValue, setGlobalFilterValue] = useState<string>("");
    const [visibleColumns, setVisibleColumns] = useState<
        Pick<IColumnBase, "label" | "name">[]
    >(columns.map((c) => ({ label: c.label, name: c.name })));
    const [expandedRows, setExpandedRows] = useState<
        DataTableValueArray | DataTableExpandedRows | undefined
    >(undefined);

    // Selection is ONLY enabled when onRowSelect is explicitly passed
    const isSelectable = !!onRowSelect;
    const [selections, setSelections] = useState<T[]>([]);

    const [serverSideRequest, setServerSideRequest] = useState<IPaginationRequest>({
        filters: filtersDefault,
        search: "",
        start: 0,
        length: 15,
        sortBy: [],
    });

    const [lockedRows, setLockedRows] = useState<T[]>([]);

    // -----------------------------------------------------------------------
    // SWR data fetching
    // -----------------------------------------------------------------------

    const fetcher: Fetcher<
        ServerResponse<IPaginationResponse<T[]>> | null,
        string
    > = useCallback(async () => {
        if (!service) return null;
        return (await service({
            ...serverSideRequest,
            filters: revertFilter(serverSideRequest.filters) as IPaginationRequest["filters"],
        })) as ServerResponse<IPaginationResponse<T[]>>;
    }, [service, serverSideRequest]);

    const swr = useSWR(id, fetcher, { revalidateOnMount: false });

    const mutate: MutatorCallback | undefined =
        service && swr.mutate ? (swr.mutate as MutatorCallback) : undefined;

    const data = swr.data
        ? (swr.data as ServerResponse<IPaginationResponse<T[]>>)
        : undefined;

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------

    function applyStateIfChanged(
        setter: React.Dispatch<React.SetStateAction<IPaginationRequest>>,
        current: IPaginationRequest,
        next: IPaginationRequest,
    ) {
        if (!isEqual(current, next)) {
            setter(next);
        }
    }

    const refresh = useCallback(
        (withLoading: boolean = true) => {
            skeleton && withLoading && setIsLoading(true);
            if (mutate) {
                mutate()
                    .then(() => {})
                    .finally(() => {
                        skeleton && withLoading && setIsLoading(false);
                    });
            } else if (staticData) {
                skeleton && withLoading && setIsLoading(false);
            }
        },
        [mutate, staticData, skeleton],
    );

    // -----------------------------------------------------------------------
    // Effects
    // -----------------------------------------------------------------------

    // CRUD refresh (bumpRefreshKey) → silent when data already loaded
    useEffect(() => {
        refresh(hasInitialData.current ? false : skeleton);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [serviceRevalidateDeps]);

    // Filter/sort/pagination change → always show skeleton
    useEffect(() => {
        refresh(skeleton);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [serverSideRequest]);

    useEffect(() => {
        if (data?.success && data.data) {
            setDataList(fixData(data.data.list));
            hasInitialData.current = true;
        } else if (staticData) {
            setDataList(fixData(staticData));
            hasInitialData.current = true;
        }
    }, [data, staticData]);

    // -----------------------------------------------------------------------
    // Derived values
    // -----------------------------------------------------------------------

    const isAnyFilter = useMemo(
        () => columns.filter((el) => !!el.filter).length > 0,
        [columns],
    );

    const allowExpansion = useMemo(() => !!rowExpansionTemplate, [rowExpansionTemplate]);

    // eslint-disable-next-line react-hooks/exhaustive-deps
    const onChangePage = useCallback(
        (event: PaginatorPageChangeEvent) => {
            applyStateIfChanged(setServerSideRequest, serverSideRequest, {
                ...serverSideRequest,
                start: event.first,
                length: event.rows,
            });
        },
        [serverSideRequest],
    );

    const pagination: PaginationState = useMemo(
        () =>
            data?.success && data.data
                ? {
                      pageSize: data.data.requestedPageSize,
                      totalRecords: data.data.total,
                      onChangePage,
                      start: data.data.pageIndex,
                  }
                : { pageSize: 0, totalRecords: 0, onChangePage, start: 0 },
        [data, onChangePage],
    );

    // -----------------------------------------------------------------------
    // Callbacks
    // -----------------------------------------------------------------------

    const onColumnToggle = useCallback(
        (selectedNames: string[]) => {
            const ordered = columns
                .filter((col) => selectedNames.some((n) => n === col.name))
                .map((c) => ({ label: c.label, name: c.name }));
            setVisibleColumns(ordered);
        },
        [columns],
    );

    const onChangeFilter: DataTableProps<T[]>["onFilter"] = useCallback(
        (event: DataTableStateEvent) => {
            const { filters, first } = event;
            applyStateIfChanged(setServerSideRequest, serverSideRequest, {
                ...serverSideRequest,
                start: first,
                filters: filters as IPaginationRequest["filters"],
            });
        },
        [serverSideRequest],
    );

    const onChangeSort: DataTableProps<T[]>["onSort"] = useCallback(
        (event: DataTableStateEvent) => {
            const { sortField, sortOrder, first } = event;
            let sortBy: DataTableSortMeta[] = [];

            if (multiSorting && event.multiSortMeta) {
                sortBy = event.multiSortMeta;
            } else if (sortOrder && sortField) {
                sortBy = [{ field: sortField, order: sortOrder }];
            }

            applyStateIfChanged(setServerSideRequest, serverSideRequest, {
                ...serverSideRequest,
                start: first,
                sortBy,
            });
        },
        [serverSideRequest, multiSorting],
    );

    const onGlobalFilterChange = useCallback(
        (value: string) => {
            applyStateIfChanged(setServerSideRequest, serverSideRequest, {
                ...serverSideRequest,
                search: value,
            });
            setGlobalFilterValue(value);
        },
        [serverSideRequest],
    );

    const onClearFilter = useCallback(() => {
        onGlobalFilterChange("");
        applyStateIfChanged(setServerSideRequest, serverSideRequest, {
            ...serverSideRequest,
            filters: filtersDefault as IPaginationRequest["filters"],
            search: "",
        });
    }, [serverSideRequest, filtersDefault, onGlobalFilterChange]);

    const onClearCache = useCallback(() => {
        localStorage.removeItem(id);
    }, [id]);

    const toggleLock = useCallback(
        (
            rowData: T,
            frozen: boolean | undefined,
            index: number,
        ) => {
            let _lockedRows: T[];
            let _unlockedRows: T[];

            if (frozen) {
                _lockedRows = lockedRows.filter((_c, i) => i !== index);
                _unlockedRows = [...dataList, rowData];
            } else {
                _unlockedRows = dataList.filter((_c, i) => i !== index);
                _lockedRows = [...lockedRows, rowData];
            }

            _unlockedRows.sort((a, b) =>
                (a["id"] as number) < (b["id"] as number) ? -1 : 1,
            );

            setLockedRows(_lockedRows);
            setDataList(_unlockedRows);
        },
        [lockedRows, dataList],
    );

    // -----------------------------------------------------------------------
    // Conditional PrimeReact DataTable props
    // -----------------------------------------------------------------------

    const conditionalProps: DataTableProps<T[]> = useMemo(() => {
        const p: DataTableProps<T[]> = {};

        if (service) {
            if (isAnyFilter) p.onFilter = onChangeFilter;
            p.onSort = onChangeSort;
        }

        if (scrollHeight) {
            p.scrollable = true;
            if (scrollHeight !== "auto") p.scrollHeight = scrollHeight;
            p.frozenValue = lockedRows as T[] & DataTableValueArray;
        }

        if (stateful && !isLoading) {
            p.onStateSave = (state) => {
                localStorage.setItem(id, JSON.stringify({ ...state, visibleColumns }));
            };
            p.onStateRestore = (state) => {
                if ("visibleColumns" in state) {
                    setVisibleColumns(
                        state.visibleColumns as Pick<IColumnBase, "label" | "name">[],
                    );
                }
            };
            p.stateStorage = "local";
            p.stateKey = id;
        }

        return p;
    }, [
        lockedRows,
        scrollHeight,
        service,
        stateful,
        visibleColumns,
        dataList,
        isLoading,
        isAnyFilter,
        onChangeFilter,
        onChangeSort,
        id,
    ]);

    // -----------------------------------------------------------------------
    // Ref
    // -----------------------------------------------------------------------

    const refValues = useMemo(
        () =>
            ({
                refresh,
                visibleColumns,
                request: serverSideRequest,
                ...tableRef.current,
            }) as IDatatableRefValues<T>,
        [refresh, visibleColumns, serverSideRequest],
    );

    useImperativeHandle(ref, () => refValues, [refValues]);

    return {
        // Refs
        tableRef,
        refValues,
        // State
        isLoading,
        dataList,
        globalFilterValue,
        visibleColumns,
        expandedRows,
        setExpandedRows,
        isSelectable,
        selections,
        setSelections,
        serverSideRequest,
        lockedRows,
        filtersDefault,
        // Derived
        isAnyFilter,
        allowExpansion,
        pagination,
        conditionalProps,
        // Callbacks
        refresh,
        onColumnToggle,
        onChangePage,
        onChangeFilter,
        onChangeSort,
        onGlobalFilterChange,
        onClearFilter,
        onClearCache,
        toggleLock,
        // Forwarded props
        columns,
        onRowSelect,
        onSelectChange,
        selectionMode,
        tableSize,
        resizableColumns,
        scrollHeight,
        stateful,
        skeleton,
        globalSearch,
        headless,
        multiSorting,
        rowLockable,
        rowExpansionTemplate,
        service,
        keyColumn,
        staticData,
        exportPDFButton,
        exportCSVButton,
        moreButtons,
        tableTitle,
        debounceFilterWaitTime,
        filterMode,
    };
}
